import time
from typing import Callable, TypeVar

T = TypeVar("T")


def with_exponential_backoff(
    fn: Callable[[], T],
    max_retries: int = 3,
    base_delay: float = 1.0,
    _sleep: Callable[[float], None] = time.sleep,  # injectable for testing
) -> T:
    """
    Call fn up to max_retries times with exponential back-off.
    Raises the last exception if all retries are exhausted.
    """
    delay = base_delay
    last_exc: Exception | None = None
    for attempt in range(max_retries + 1):
        try:
            return fn()
        except Exception as exc:
            last_exc = exc
            if attempt < max_retries:
                _sleep(delay)
                delay *= 2
    assert last_exc is not None
    raise last_exc


# tests/test_retry.py
import pytest
from unittest.mock import MagicMock, call
from src.agent.retry import with_exponential_backoff


def test_success_on_first_try_no_sleep():
    mock_sleep = MagicMock()
    fn = MagicMock(return_value="ok")
    result = with_exponential_backoff(fn, max_retries=3, _sleep=mock_sleep)
    assert result == "ok"
    fn.assert_called_once()
    mock_sleep.assert_not_called()


def test_retries_on_exception_then_succeeds():
    mock_sleep = MagicMock()
    fn = MagicMock(side_effect=[ValueError("fail"), ValueError("fail"), "success"])
    result = with_exponential_backoff(
        fn, max_retries=3, base_delay=1.0, _sleep=mock_sleep
    )
    assert result == "success"
    assert fn.call_count == 3
    assert mock_sleep.call_count == 2
    assert mock_sleep.call_args_list == [call(1.0), call(2.0)]


def test_raises_after_all_retries_exhausted():
    mock_sleep = MagicMock()
    fn = MagicMock(side_effect=RuntimeError("always fails"))
    with pytest.raises(RuntimeError, match="always fails"):
        with_exponential_backoff(fn, max_retries=2, _sleep=mock_sleep)
    assert fn.call_count == 3  # 1 initial + 2 retries
    assert mock_sleep.call_count == 2


def test_delay_doubles_on_each_retry():
    mock_sleep = MagicMock()
    fn = MagicMock(side_effect=[ValueError(), ValueError(), ValueError(), "done"])
    with_exponential_backoff(fn, max_retries=3, base_delay=0.5, _sleep=mock_sleep)
    assert mock_sleep.call_args_list == [call(0.5), call(1.0), call(2.0)]

