from typing import Any, Callable
import json


class UnknownToolError(Exception):
    pass


class ToolDispatcher:
    def __init__(self, tool_registry: dict[str, Callable[..., Any]]):
        self._registry = tool_registry

    def dispatch(
        self, tool_name: str, tool_input: dict[str, Any], tool_use_id: str
    ) -> dict[str, Any]:
        """
        Call the named tool and return a tool_result message dict.
        Raises UnknownToolError if tool_name is not in the registry.
        Wraps tool execution errors as error-type tool_result blocks.
        """
        if tool_name not in self._registry:
            raise UnknownToolError(f"No tool registered: {tool_name!r}")

        try:
            result = self._registry[tool_name](**tool_input)
        except Exception as exc:
            return {
                "role": "user",
                "content": [{
                    "type": "tool_result",
                    "tool_use_id": tool_use_id,
                    "is_error": True,
                    "content": str(exc),
                }],
            }

        return {
            "role": "user",
            "content": [{
                "type": "tool_result",
                "tool_use_id": tool_use_id,
                "content": json.dumps(result),
            }],
        }


# tests/test_dispatcher.py
import pytest
from unittest.mock import MagicMock
from src.agent.dispatcher import ToolDispatcher, UnknownToolError


def test_dispatch_calls_registered_tool():
    fake_tool = MagicMock(return_value={"answer": 42})
    dispatcher = ToolDispatcher({"calculator": fake_tool})
    result = dispatcher.dispatch("calculator", {"expression": "6*7"}, "tu_01")
    fake_tool.assert_called_once_with(expression="6*7")
    assert result["content"][0]["type"] == "tool_result"
    assert "42" in result["content"][0]["content"]


def test_dispatch_raises_for_unknown_tool():
    dispatcher = ToolDispatcher({})
    with pytest.raises(UnknownToolError, match="No tool registered: 'missing_tool'"):
        dispatcher.dispatch("missing_tool", {}, "tu_02")


def test_dispatch_wraps_tool_exception_as_error_block():
    failing_tool = MagicMock(side_effect=ValueError("connection refused"))
    dispatcher = ToolDispatcher({"fetch": failing_tool})
    result = dispatcher.dispatch("fetch", {"url": "http://example.com"}, "tu_03")
    block = result["content"][0]
    assert block["is_error"] is True
    assert "connection refused" in block["content"]
    assert block["tool_use_id"] == "tu_03"


def test_dispatch_passes_kwargs_to_tool():
    tool = MagicMock(return_value="ok")
    dispatcher = ToolDispatcher({"t": tool})
    dispatcher.dispatch("t", {"key1": "val1", "key2": 99}, "tu_04")
    tool.assert_called_once_with(key1="val1", key2=99)


@pytest.mark.parametrize("n_calls", [1, 3, 10])
def test_dispatch_tool_called_exactly_once_per_invocation(n_calls):
    tool = MagicMock(return_value={})
    dispatcher = ToolDispatcher({"t": tool})
    for i in range(n_calls):
        dispatcher.dispatch("t", {}, f"tu_{i}")
    assert tool.call_count == n_calls
